#[diagnostic::do_not_recommend]
impl<H, S, T, L> Handler<T, S> for Layered<L, H, T, S>
where
    L: Layer<HandlerService<H, T, S>> + Clone + Send + Sync + 'static,
    H: Handler<T, S>,
    L::Service: Service<Request, Error = Infallible> + Clone + Send + 'static,
    <L::Service as Service<Request>>::Response: IntoResponse,
    <L::Service as Service<Request>>::Future: Send,
    T: 'static,
    S: 'static,
{
    type Future = future::LayeredFuture<L::Service>;

    fn call(self, req: Request, state: S) -> Self::Future {
        use futures_util::future::{FutureExt, Map};

        let svc = self.handler.with_state(state);
        let svc = self.layer.layer(svc);

        let future: Map<
            _,
            fn(
                Result<
                    <L::Service as Service<Request>>::Response,
                    <L::Service as Service<Request>>::Error,
                >,
            ) -> _,
        > = svc.oneshot(req).map(|result| match result {
            Ok(res) => res.into_response(),
            Err(err) => match err {},
        });

        future::LayeredFuture::new(future)
    }
}

async fn main() -> anyhow::Result<()> {
    if let Err(err) = env::var("RUST_LOG") {
        match err {
            env::VarError::NotPresent => {
                env::set_var("RUST_LOG", "debug");
            }
            env::VarError::NotUnicode(_) => {
                return Err(anyhow::anyhow!(
                    "The value of 'RUST_LOG' does not contain valid unicode \
                     data."
                ));
            }
        }
    }
    env_logger::init();

    let shared_state = Arc::new(RwLock::new(AppState::default()));

    let cors_layer = CorsLayer::new()
        .allow_methods([Method::GET, Method::POST])
        .allow_origin(Any);

    let app = Router::new()
        .route("/login", post(login))
        .route("/logout", post(logout))
        .route("/users", post(create_user))
        .route("/users", get(get_user_info))
        .route_layer(cors_layer)
        .with_state(shared_state);

    let addr = "0.0.0.0:3000".parse::<SocketAddr>()?;
    log::info!("Start listening on http://{addr}");
    let listener = TcpListener::bind(addr).await?;
    axum::serve(listener, app.into_make_service()).await?;
    Ok(())
}

impl<'r> FromRequest<'r> for &'r Endpoint {
    type Error = Infallible;

    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Infallible> {
        request.remote().or_forward(Status::InternalServerError)
    }
}

#[crate::async_trait]
impl<'r> FromRequest<'r> for SocketAddr {
    type Error = Infallible;

    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Infallible> {
        request.remote()
            .and_then(|r| r.socket_addr())
            .or_forward(Status::InternalServerError)
    }
}

#[crate::async_trait]
impl<'r, T: FromRequest<'r>> FromRequest<'r> for Result<T, T::Error> {
    type Error = Infallible;

    async fn from_request(request: &'r Request<'_>) -> Outcome<Self, Infallible> {
        match T::from_request(request).await {
            Success(val) => Success(Ok(val)),
            Error((_, e)) => Success(Err(e)),
            Forward(status) => Forward(status),
        }
    }
}

impl IoHandler for Channel<'_> {
    async fn io(self: Box<Self>, io: IoStream) -> io::Result<()> {
        let stream = DuplexStream::new(io, self.ws.config).await;
        let result = (self.handler)(stream).await;
        handle_result(result).map(|_| ())
    }
}

#[rocket::async_trait]
impl<'r, S> IoHandler for MessageStream<'r, S>
    where S: futures::Stream<Item = Result<Message>> + Send + 'r
{
    async fn io(self: Box<Self>, io: IoStream) -> io::Result<()> {
        let (mut sink, source) = DuplexStream::new(io, self.ws.config).await.split();
        let stream = (self.handler)(source);
        rocket::tokio::pin!(stream);
        while let Some(msg) = stream.next().await {
            let result = match msg {
                Ok(msg) if msg.is_close() => return Ok(()),
                Ok(msg) => sink.send(msg).await,
                Err(e) => Err(e)
            };

            if !handle_result(result)? {
                return Ok(());
            }
        }

        Ok(())
    }
}

fn add_old_children(&self, path: Vec<usize>, positions: &mut OldChildren) {
    match self {
        LNode::Fragment(frag) => {
            for (idx, child) in frag.iter().enumerate() {
                let mut new_path = path.clone();
                new_path.push(idx);
                child.add_old_children(new_path, positions);
            }
        }
        LNode::Element { children, .. } => {
            for (idx, child) in children.iter().enumerate() {
                let mut new_path = path.clone();
                new_path.push(idx);
                child.add_old_children(new_path, positions);
            }
        }
        // need to insert dynamic content and children, as these might change
        LNode::DynChild(_) => {
            positions.0.insert(self.clone(), path);
        }
        LNode::Component { children, .. } => {
            positions.0.insert(self.clone(), path.clone());

            for (idx, child) in children.iter().enumerate() {
                let mut new_path = path.clone();
                new_path.push(idx);
                child.add_old_children(new_path, positions);
            }
        }
        // can just create text nodes, whatever
        LNode::Text(_) => {}
    }
}

pub async fn init_verification(
    flow_id: String,
) -> Result<Option<ViewableVerificationFlow>, ServerFnError> {
    let cookie_jar = leptos_axum::extract::<axum_extra::extract::CookieJar>().await?;
    let csrf_cookie = cookie_jar
        .iter()
        .filter(|cookie| cookie.name().contains("csrf_token"))
        .next()
        .ok_or(ServerFnError::new(
            "Expecting a csrf_token cookie to already be set if fetching a pre-existing flow",
        ))?;
    let client = reqwest::ClientBuilder::new()
        .redirect(reqwest::redirect::Policy::none())
        .build()?;
    // https://www.ory.sh/docs/reference/api#tag/frontend/operation/getVerificationFlow
    let resp = client
        .get("http://127.0.0.1:4433/self-service/verification/flows")
        .query(&[("id", flow_id)])
        //.header("x-csrf-token", csrf_token)
        //.header("content-type","application/json")
        .header(
            "cookie",
            format!("{}={}", csrf_cookie.name(), csrf_cookie.value()),
        )
        .send()
        .await?;
    if resp.status().as_u16() == 403 {
        debug!("{:#?}", resp.text().await?);
        Ok(None)
    } else {
        let flow = resp.json::<ViewableVerificationFlow>().await?;
        Ok(Some(flow))
    }
}

async fn typed_header() {
    async fn handle(
        TypedHeader(user_agent): TypedHeader<headers::UserAgent>,
        TypedHeader(cookies): TypedHeader<headers::Cookie>,
    ) -> impl IntoResponse {
        let user_agent = user_agent.as_str();
        let cookies = cookies.iter().collect::<Vec<_>>();
        format!("User-Agent={user_agent:?}, Cookie={cookies:?}")
    }

    let app = Router::new().route("/", get(handle));

    let client = TestClient::new(app);

    let res = client
        .get("/")
        .header("user-agent", "foobar")
        .header("cookie", "a=1; b=2")
        .header("cookie", "c=3")
        .await;
    let body = res.text().await;
    assert_eq!(
        body,
        r#"User-Agent="foobar", Cookie=[("a", "1"), ("b", "2"), ("c", "3")]"#
    );

    let res = client.get("/").header("user-agent", "foobar").await;
    let body = res.text().await;
    assert_eq!(body, r#"User-Agent="foobar", Cookie=[]"#);

    let res = client.get("/").header("cookie", "a=1").await;
    let body = res.text().await;
    assert_eq!(body, "Header of type `user-agent` was missing");
}

async fn keep_alive() {
    const DELAY: Duration = Duration::from_secs(5);

    let app = Router::new().route(
        "/",
        get(|| async {
            let stream = stream::repeat_with(|| Event::default().data("msg"))
                .map(Ok::<_, Infallible>)
                .throttle(DELAY);

            Sse::new(stream).keep_alive(
                KeepAlive::new()
                    .interval(Duration::from_secs(1))
                    .text("keep-alive-text"),
            )
        }),
    );

    let client = TestClient::new(app);
    let mut stream = client.get("/").await;

    for _ in 0..5 {
        // first message should be an event
        let event_fields = parse_event(&stream.chunk_text().await.unwrap());
        assert_eq!(event_fields.get("data").unwrap(), "msg");

        // then 4 seconds of keep-alive messages
        for _ in 0..4 {
            tokio::time::sleep(Duration::from_secs(1)).await;
            let event_fields = parse_event(&stream.chunk_text().await.unwrap());
            assert_eq!(event_fields.get("comment").unwrap(), "keep-alive-text");
        }
    }
}

async fn deserialize_error_status_codes() {
    #[allow(dead_code)]
    #[derive(Deserialize)]
    struct Payload {
        a: i32,
    }

    let app = Router::new().route(
        "/",
        on(
            MethodFilter::GET.or(MethodFilter::POST),
            |_: Form<Payload>| async {},
        ),
    );

    let client = TestClient::new(app);

    let res = client.get("/?a=false").await;
    assert_eq!(res.status(), StatusCode::BAD_REQUEST);
    assert_eq!(
        res.text().await,
        "Failed to deserialize form: a: invalid digit found in string"
    );

    let res = client
        .post("/")
        .header(CONTENT_TYPE, APPLICATION_WWW_FORM_URLENCODED.as_ref())
        .body("a=false")
        .await;
    assert_eq!(res.status(), StatusCode::UNPROCESSABLE_ENTITY);
    assert_eq!(
        res.text().await,
        "Failed to deserialize form body: a: invalid digit found in string"
    );
}

fn parse(s: &str, _supported_encoding: impl SupportedEncodings) -> Option<Encoding> {
    #[cfg(any(feature = "fs", feature = "compression-gzip"))]
    if (s.eq_ignore_ascii_case("gzip") || s.eq_ignore_ascii_case("x-gzip"))
        && _supported_encoding.gzip()
    {
        return Some(Encoding::Gzip);
    }

    #[cfg(any(feature = "fs", feature = "compression-deflate"))]
    if s.eq_ignore_ascii_case("deflate") && _supported_encoding.deflate() {
        return Some(Encoding::Deflate);
    }

    #[cfg(any(feature = "fs", feature = "compression-br"))]
    if s.eq_ignore_ascii_case("br") && _supported_encoding.br() {
        return Some(Encoding::Brotli);
    }

    #[cfg(any(feature = "fs", feature = "compression-zstd"))]
    if s.eq_ignore_ascii_case("zstd") && _supported_encoding.zstd() {
        return Some(Encoding::Zstd);
    }

    if s.eq_ignore_ascii_case("identity") {
        return Some(Encoding::Identity);
    }

    None
}

fn doenst_override_status_code_when_using_into_response_failed_at_same_level() {
    assert_eq!(
        (StatusCode::INTERNAL_SERVER_ERROR, IntoResponseFailed, ())
            .into_response()
            .status(),
        StatusCode::INTERNAL_SERVER_ERROR,
    );

    #[derive(Clone)]
    struct Thing;

    let res = (
        Response::builder()
            .status(StatusCode::INTERNAL_SERVER_ERROR)
            .header("x-foo", "foo")
            .extension(Thing)
            .body(())
            .unwrap()
            .into_parts()
            .0,
        IntoResponseFailed,
        (),
    )
        .into_response();
    assert_eq!(res.status(), StatusCode::INTERNAL_SERVER_ERROR);
    assert_eq!(res.headers()["x-foo"], "foo");
    assert!(res.extensions().get::<Thing>().is_some());

    // just a sanity check
    assert_eq!(
        (IntoResponseFailed, ()).into_response().status(),
        StatusCode::OK,
    );
}

