pub(crate) fn send_pending_ping<T, B>(
    &mut self,
    cx: &mut Context,
    dst: &mut Codec<T, B>,
) -> Poll<io::Result<()>>
where
    T: AsyncWrite + Unpin,
    B: Buf,
{
    if let Some(ref mut ping) = self.pending_ping {
        if !ping.sent {
            if !dst.poll_ready(cx)?.is_ready() {
                return Poll::Pending;
            }

            dst.buffer(Ping::new(ping.payload).into())
                .expect("invalid ping frame");
            ping.sent = true;
        }
    } else if let Some(ref users) = self.user_pings {
        if users.0.state.load(Ordering::Acquire) == USER_STATE_PENDING_PING {
            if !dst.poll_ready(cx)?.is_ready() {
                return Poll::Pending;
            }

            dst.buffer(Ping::new(Ping::USER).into())
                .expect("invalid ping frame");
            users
                .0
                .state
                .store(USER_STATE_PENDING_PONG, Ordering::Release);
        } else {
            users.0.ping_task.register(cx.waker());
        }
    }

    Poll::Ready(Ok(()))
}

pub fn from_parts(src: Parts) -> Result<Uri, InvalidUriParts> {
    if src.scheme.is_some() {
        if src.authority.is_none() {
            return Err(ErrorKind::AuthorityMissing.into());
        }

        if src.path_and_query.is_none() {
            return Err(ErrorKind::PathAndQueryMissing.into());
        }
    } else if src.authority.is_some() && src.path_and_query.is_some() {
        return Err(ErrorKind::SchemeMissing.into());
    }

    let scheme = match src.scheme {
        Some(scheme) => scheme,
        None => Scheme {
            inner: Scheme2::None,
        },
    };

    let authority = match src.authority {
        Some(authority) => authority,
        None => Authority::empty(),
    };

    let path_and_query = match src.path_and_query {
        Some(path_and_query) => path_and_query,
        None => PathAndQuery::empty(),
    };

    Ok(Uri {
        scheme,
        authority,
        path_and_query,
    })
}

pub(super) fn buffer<BB: Buf + Into<B>>(&mut self, mut buf: BB) {
    debug_assert!(buf.has_remaining());
    match self.strategy {
        WriteStrategy::Flatten => {
            let head = self.headers_mut();

            head.maybe_unshift(buf.remaining());
            trace!(
                self.len = head.remaining(),
                buf.len = buf.remaining(),
                "buffer.flatten"
            );
            //perf: This is a little faster than <Vec as BufMut>>::put,
            //but accomplishes the same result.
            loop {
                let adv = {
                    let slice = buf.chunk();
                    if slice.is_empty() {
                        return;
                    }
                    head.bytes.extend_from_slice(slice);
                    slice.len()
                };
                buf.advance(adv);
            }
        }
        WriteStrategy::Queue => {
            trace!(
                self.len = self.remaining(),
                buf.len = buf.remaining(),
                "buffer.queue"
            );
            self.queue.push(buf.into());
        }
    }
}

fn recv_next_result_column(def: &ColumnDefinition, ordinal: usize) -> Result<MySqlColumn, Error> {
    // if the alias is empty, use the alias
    // only then use the name
    let column_name = def.name()?;

    let name = match (def.name()?, def.alias()?) {
        (_, alias) if !alias.is_empty() => UStr::new(alias),
        (name, _) => UStr::new(name),
    };

    let table = def.table()?;

    let origin = if table.is_empty() {
        ColumnOrigin::Expression
    } else {
        let schema = def.schema()?;

        ColumnOrigin::Table(TableColumn {
            table: if !schema.is_empty() {
                format!("{schema}.{table}").into()
            } else {
                table.into()
            },
            name: column_name.into(),
        })
    };

    let type_info = MySqlTypeInfo::from_column(def);

    Ok(MySqlColumn {
        name,
        type_info,
        ordinal,
        flags: Some(def.flags),
        origin,
    })
}

pub fn transition_after(&mut self, mut stream: store::Ptr, is_reset_counted: bool) {
    tracing::trace!(
        "transition_after; stream={:?}; state={:?}; is_closed={:?}; \
         pending_send_empty={:?}; buffered_send_data={}; \
         num_recv={}; num_send={}",
        stream.id,
        stream.state,
        stream.is_closed(),
        stream.pending_send.is_empty(),
        stream.buffered_send_data,
        self.num_recv_streams,
        self.num_send_streams
    );

    if stream.is_closed() {
        if !stream.is_pending_reset_expiration() {
            stream.unlink();
            if is_reset_counted {
                self.dec_num_reset_streams();
            }
        }

        if !stream.state.is_scheduled_reset() && stream.is_counted {
            tracing::trace!("dec_num_streams; stream={:?}", stream.id);
            // Decrement the number of active streams.
            self.dec_num_streams(&mut stream);
        }
    }

    // Release the stream if it requires releasing
    if stream.is_released() {
        stream.remove();
    }
}

pub fn flush(&mut self, cx: &mut Context) -> Poll<io::Result<()>> {
    let span = tracing::trace_span!("FramedWrite::flush");
    let _e = span.enter();

    loop {
        while !self.encoder.is_empty() {
            match self.encoder.next {
                Some(Next::Data(ref mut frame)) => {
                    tracing::trace!(queued_data_frame = true);
                    let mut buf = (&mut self.encoder.buf).chain(frame.payload_mut());
                    ready!(poll_write_buf(Pin::new(&mut self.inner), cx, &mut buf))?
                }
                _ => {
                    tracing::trace!(queued_data_frame = false);
                    ready!(poll_write_buf(
                        Pin::new(&mut self.inner),
                        cx,
                        &mut self.encoder.buf
                    ))?
                }
            };
        }

        match self.encoder.unset_frame() {
            ControlFlow::Continue => (),
            ControlFlow::Break => break,
        }
    }

    tracing::trace!("flushing buffer");
    // Flush the upstream
    ready!(Pin::new(&mut self.inner).poll_flush(cx))?;

    Poll::Ready(Ok(()))
}

fn decode<'i, I: Iterator<Item = &'i HeaderValue>>(values: &mut I) -> Result<Self, Error> {
    values
        .next()
        .and_then(|v| v.to_str().ok())
        .and_then(|s| split_in_two(s, ' '))
        .and_then(|(unit, spec)| {
            if unit != "bytes" {
                // For now, this only supports bytes-content-range. nani?
                return None;
            }

            let (range, complete_length) = split_in_two(spec, '/')?;

            let complete_length = if complete_length == "*" {
                None
            } else {
                Some(complete_length.parse().ok()?)
            };

            let range = if range == "*" {
                None
            } else {
                let (first_byte, last_byte) = split_in_two(range, '-')?;
                let first_byte = first_byte.parse().ok()?;
                let last_byte = last_byte.parse().ok()?;
                if last_byte < first_byte {
                    return None;
                }
                Some((first_byte, last_byte))
            };

            Some(ContentRange {
                range,
                complete_length,
            })
        })
        .ok_or_else(Error::invalid)
}

macro_rules! opaque_future {
    ($(#[$m:meta])* pub type $name:ident<$($param:ident),+> = $actual:ty;) => {
        pin_project_lite::pin_project! {
            $(#[$m])*
            pub struct $name<$($param),+> {
                #[pin]
                inner: $actual
            }
        }

        impl<$($param),+> $name<$($param),+> {
            pub(crate) fn new(inner: $actual) -> Self {
                Self {
                    inner
                }
            }
        }

        impl<$($param),+> std::fmt::Debug for $name<$($param),+> {
            fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
                f.debug_tuple(stringify!($name)).field(&format_args!("...")).finish()
            }
        }

        impl<$($param),+> std::future::Future for $name<$($param),+>
        where
            $actual: std::future::Future,
        {
            type Output = <$actual as std::future::Future>::Output;
            #[inline]
            fn poll(self: std::pin::Pin<&mut Self>, cx: &mut std::task::Context<'_>) -> std::task::Poll<Self::Output> {
                self.project().inner.poll(cx)
            }
        }
    }
}

fn expand_derive_has_sql_type_struct(
    input: &DeriveInput,
    fields: &Punctuated<Field, Comma>,
) -> syn::Result<TokenStream> {
    let attributes = check_struct_attributes(input, fields)?;

    let ident = &input.ident;
    let mut tts = TokenStream::new();

    if cfg!(feature = "postgres") {
        let ty_name = type_name(ident, attributes.type_name.as_ref());

        tts.extend(quote!(
            #[automatically_derived]
            impl ::sqlx::Type<::sqlx::Postgres> for #ident {
                fn type_info() -> ::sqlx::postgres::PgTypeInfo {
                    ::sqlx::postgres::PgTypeInfo::with_name(#ty_name)
                }
            }
        ));

        if !attributes.no_pg_array {
            tts.extend(quote!(
                #[automatically_derived]
                impl ::sqlx::postgres::PgHasArrayType for #ident  {
                    fn array_type_info() -> ::sqlx::postgres::PgTypeInfo {
                        ::sqlx::postgres::PgTypeInfo::array_of(#ty_name)
                    }
                }
            ));
        }
    }

    Ok(tts)
}

fn expand_derive_has_sql_type_weak_enum(
    input: &DeriveInput,
    variants: &Punctuated<Variant, Comma>,
) -> syn::Result<TokenStream> {
    let attrs = check_weak_enum_attributes(input, variants)?;
    let repr = attrs.repr.unwrap();
    let ident = &input.ident;
    let mut ts = quote!(
        #[automatically_derived]
        impl<DB: ::sqlx::Database> ::sqlx::Type<DB> for #ident
        where
            #repr: ::sqlx::Type<DB>,
        {
            fn type_info() -> DB::TypeInfo {
                <#repr as ::sqlx::Type<DB>>::type_info()
            }

            fn compatible(ty: &DB::TypeInfo) -> bool {
                <#repr as ::sqlx::Type<DB>>::compatible(ty)
            }
        }
    );

    if cfg!(feature = "postgres") && !attrs.no_pg_array {
        ts.extend(quote!(
            #[automatically_derived]
            impl ::sqlx::postgres::PgHasArrayType for #ident  {
                fn array_type_info() -> ::sqlx::postgres::PgTypeInfo {
                    <#repr as ::sqlx::postgres::PgHasArrayType>::array_type_info()
                }
            }
        ));
    }

    Ok(ts)
}

pub fn value_eq(&self, other: &Header) -> bool {
    match *self {
        Header::Field { ref value, .. } => {
            let a = value;
            match *other {
                Header::Field { ref value, .. } => a == value,
                _ => false,
            }
        }
        Header::Authority(ref a) => match *other {
            Header::Authority(ref b) => a == b,
            _ => false,
        },
        Header::Method(ref a) => match *other {
            Header::Method(ref b) => a == b,
            _ => false,
        },
